def assert_vs3_no_claim_boundary(testcase: unittest.TestCase, boundary: dict[str, object]) -> None:
    testcase.assertTrue(boundary["h_rows_remain_human_required"])
    testcase.assertTrue(boundary["structural_validation_is_not_acceptance"])
    testcase.assertIn("validation_surface", boundary)
    for key in VS3_HUMAN_GATE_NO_CLAIM_FALSE_KEYS:
        testcase.assertIn(key, boundary)
        testcase.assertFalse(boundary[key], key)


def assert_vs3_summary_no_readiness_claims(testcase: unittest.TestCase, summary: dict[str, object]) -> None:
    for key in VS3_SUMMARY_NO_READINESS_CLAIM_KEYS:
        testcase.assertIn(key, summary)
        testcase.assertFalse(summary[key], key)


def run_cli(*args: str) -> subprocess.CompletedProcess[str]:
    env = os.environ.copy()
    env["PATH"] = f"{ROOT}{os.pathsep}{env.get('PATH', '')}"
    return subprocess.run(
        ["cornerstone", *args],
        cwd=ROOT,
        env=env,
        text=True,
        capture_output=True,
        check=False,
    )


class ScaffoldCliTests(unittest.TestCase):
    def test_source_snapshot_expands_dirty_directory_to_hashable_files(self) -> None:
        snapshot_root = ROOT / "tmp/test-source-snapshot-directory"
        if snapshot_root.exists():
            shutil.rmtree(snapshot_root)
        try:
            fixture_dir = snapshot_root / "fixtures/connectorhub/contracts"
            fixture_dir.mkdir(parents=True)
            fixture_file = fixture_dir / "sample.json"
            fixture_file.write_text('{"scenario":"CS-CH-001"}\n')

            snapshot = _source_snapshot(
                snapshot_root,
                "base",
                "tree",
                [{"status": "??", "path": "fixtures/connectorhub/"}],
            )
            self.assertEqual(len(snapshot["paths"]), 1)
            self.assertEqual(snapshot["paths"][0]["path"], "fixtures/connectorhub/contracts/sample.json")
            self.assertEqual(snapshot["paths"][0]["state"], "present")
            self.assertIsInstance(snapshot["paths"][0]["sha256"], str)
            self.assertEqual(len(snapshot["paths"][0]["sha256"]), 64)
        finally:
            if snapshot_root.exists():
                shutil.rmtree(snapshot_root)

    def test_source_snapshot_excludes_generated_report_roots(self) -> None:
        snapshot_root = ROOT / "tmp/test-source-snapshot-reports"
        if snapshot_root.exists():
            shutil.rmtree(snapshot_root)
        try:
            source_file = snapshot_root / "packages/cornerstone_cli/sample.py"
            source_file.parent.mkdir(parents=True)
            source_file.write_text("print('source')\n")
            source_contract = snapshot_root / "docs/scenario-contracts/VS3_TEST_CONTRACT.md"
            source_contract.parent.mkdir(parents=True)
            source_contract.write_text("# VS3 test contract\n")
            for report_path in [
                "docs/verification-reports/VS3_SCENARIO_GATE_COMPONENT_PROOF_GUARD_CHECKPOINT_2026-06-30.md",
                "reports/human-gates/vs3/VS3-H01.json",
                "reports/observability/vs3-observability-proof.json",
                "reports/runtime/vs3-tool-registry-state/audit/events.jsonl",
                "reports/security/vs3-final-regression-proof.json",
            ]:
                path = snapshot_root / report_path
                path.parent.mkdir(parents=True, exist_ok=True)
                path.write_text("{}\n")

            snapshot = _source_snapshot(
                snapshot_root,
                "base",
                "tree",
                [
                    {"status": "M", "path": "packages/cornerstone_cli/sample.py"},
                    {"status": "??", "path": "docs/"},
                    {"status": "??", "path": "reports/human-gates/"},
                    {"status": "??", "path": "reports/observability/"},
                    {"status": "??", "path": "reports/runtime/"},
                    {"status": "M", "path": "reports/security/vs3-final-regression-proof.json"},
                ],
            )

            self.assertEqual(
                [entry["path"] for entry in snapshot["paths"]],
                [
                    "docs/scenario-contracts/VS3_TEST_CONTRACT.md",
                    "packages/cornerstone_cli/sample.py",
                ],
            )
        finally:
            if snapshot_root.exists():
                shutil.rmtree(snapshot_root)

    def test_vs2_regression_guard_transcript_keeps_nested_regressions_explicit(self) -> None:
        original = os.environ.get("CORNERSTONE_SKIP_VS2_REGRESSION_TESTS")
        try:
            os.environ["CORNERSTONE_SKIP_VS2_REGRESSION_TESTS"] = "1"
            self.assertTrue(_vs2_regression_guard_enabled())
        finally:
            if original is None:
                os.environ.pop("CORNERSTONE_SKIP_VS2_REGRESSION_TESTS", None)
            else:
                os.environ["CORNERSTONE_SKIP_VS2_REGRESSION_TESTS"] = original

        transcript = _vs2_regression_guard_transcript(
            ["make", "verify-vs0-evux"],
            report_refs=["reports/vs2/regression/vs0-evux.json"],
        )
        self.assertEqual(transcript["schema_version"], "cs.command_transcript.v0")
        self.assertEqual(transcript["command"], ["make", "verify-vs0-evux"])
        self.assertEqual(transcript["exit_code"], 0)
        self.assertFalse(transcript["timed_out"])
        self.assertTrue(transcript["skipped_by_vs2_regression_guard"])
        self.assertIn("reports/vs2/regression/vs0-evux.json", transcript["report_refs"])

    def test_version_json(self) -> None:
        result = run_cli("version", "--json")
        self.assertEqual(result.returncode, 0, result.stderr)
        payload = json.loads(result.stdout)
        self.assertEqual(payload["schema_version"], "cs.cli.v0")
        self.assertEqual(payload["status"], "success")

    def test_ready_reports_local_runtime_without_production_overclaim(self) -> None:
        result = run_cli("ready", "--json")
        self.assertEqual(result.returncode, 0, result.stdout)
        payload = json.loads(result.stdout)
        self.assertEqual(payload["status"], "success")
        self.assertFalse(payload["errors"])
        checks = {row["name"]: row["present"] for row in payload["checks"]}
        self.assertTrue(checks["fixture_corpus"])
        self.assertTrue(checks["api_runtime"])
        self.assertTrue(checks["web_runtime"])
        self.assertTrue(payload["readiness"]["local_scenario_ready"])
        self.assertTrue(payload["readiness"]["vs0_runtime_ready"])
        self.assertFalse(payload["readiness"]["production_release_ready"])
        self.assertTrue(payload["readiness"]["human_required"])
        self.assertEqual(payload["readiness"]["real_external_http_calls"], 0)
        runtime_report = payload["readiness"]["last_successful_runtime_scenario"]
        self.assertEqual(runtime_report["scenario_set"], "vs0-product-runtime")
        self.assertEqual(runtime_report["path"], "reports/scenario/vs0-product-runtime-2026-06-11.json")
        self.assertEqual(runtime_report["gate_status"], "pass")
        self.assertEqual(runtime_report["blocking"], 0)
        acceptance_report = payload["readiness"]["last_successful_acceptance_scenario"]
        if acceptance_report["path"] is not None:
            self.assertEqual(acceptance_report["scenario_set"], "vs0-runtime-acceptance")
            self.assertEqual(acceptance_report["gate_status"], "pass")
            self.assertEqual(payload["readiness"]["acceptance_gate"]["status"], "pass")

