            self.assertEqual(payload["claim_boundary"]["vs3_l"], "NOT_CLAIMED")
            self.assertEqual(payload["claim_boundary"]["vs3_p"], "NOT_CLAIMED")
            self.assertEqual(payload["claim_boundary"]["production_onprem"], "NOT_CLAIMED")
